# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;
using System.Collections.Generic;

public class PlayerStats : MonoBehaviour
{
    public int maxHealth = 100;
    public int currentHealth = 100;
    public int currency = 0;
    public int attackDamage = 10;
    public int defense = 5;
    public int level = 1;
    
    public void TakeDamage(int damage)
    {
        int calculatedDamage = Mathf.Max(0, damage - defense);
        currentHealth -= calculatedDamage;
        
        if (currentHealth <= 0)
        {
            currentHealth = 0;
            Die();
        }
        
        Debug.Log("Took " + calculatedDamage + " damage. Health: " + currentHealth);
    }
    
    public void Heal(int amount)
    {
        currentHealth += amount;
        if (currentHealth > maxHealth)
        {
            currentHealth = maxHealth;
        }
        Debug.Log("Healed " + amount + ". Health: " + currentHealth);
    }
    
    public void AddCurrency(int amount)
    {
        currency += amount;
        Debug.Log("Added " + amount + " currency. Total: " + currency);
    }
    
    public bool SpendCurrency(int amount)
    {
        if (currency >= amount)
        {
            currency -= amount;
            Debug.Log("Spent " + amount + " currency. Remaining: " + currency);
            return true;
        }
        Debug.Log("Not enough currency!");
        return false;
    }
    
    public int CalculateDamageOutput()
    {
        return attackDamage * level;
    }
    
    void Die()
    {
        Debug.Log("Player died!");
    }
}

public class Enemy : MonoBehaviour
{
    public int health = 50;
    public int damage = 15;
    public int currencyReward = 10;
    
    private PlayerStats player;
    
    void Start()
    {
        player = FindObjectOfType<PlayerStats>();
    }
    
    public void TakeDamage(int damage)
    {
        health -= damage;
        Debug.Log("Enemy took " + damage + " damage. Health: " + health);
        
        if (health <= 0)
        {
            Die();
        }
    }
    
    public void AttackPlayer()
    {
        if (player != null)
        {
            player.TakeDamage(damage);
        }
    }
    
    void Die()
    {
        if (player != null)
        {
            player.AddCurrency(currencyReward);
        }
        Destroy(gameObject);
    }
}

public class ShopItem
{
    public string itemName;
    public int price;
    public string itemType;
    public int value;
    
    public ShopItem(string name, int price, string type, int value)
    {
        this.itemName = name;
        this.price = price;
        this.itemType = type;
        this.value = value;
    }
}

public class Shop : MonoBehaviour
{
    private PlayerStats player;
    public List<ShopItem> shopItems = new List<ShopItem>();
    
    void Start()
    {
        player = FindObjectOfType<PlayerStats>();
        InitializeShop();
    }
    
    void InitializeShop()
    {
        shopItems.Add(new ShopItem("Health Potion", 50, "heal", 30));
        shopItems.Add(new ShopItem("Small Currency Pack", 100, "currency", 500));
        shopItems.Add(new ShopItem("Medium Currency Pack", 250, "currency", 1500));
        shopItems.Add(new ShopItem("Large Currency Pack", 500, "currency", 3500));
        shopItems.Add(new ShopItem("Sword Upgrade", 200, "damage", 5));
        shopItems.Add(new ShopItem("Armor Upgrade", 200, "defense", 3));
        shopItems.Add(new ShopItem("Max Health Upgrade", 300, "maxHealth", 20));
        shopItems.Add(new ShopItem("Level Up", 500, "level", 1));
    }
    
    public int CalculateItemPrice(ShopItem item)
    {
        return item.price;
    }
    
    public int CalculateDiscountedPrice(ShopItem item, float discountPercent)
    {
        return Mathf.FloorToInt(item.price * (1f - discountPercent / 100f));
    }
    
    public bool PurchaseItem(ShopItem item)
    {
        int finalPrice = CalculateItemPrice(item);
        
        if (player.SpendCurrency(finalPrice))
        {
            ApplyItemEffect(item);
            Debug.Log("Purchased: " + item.itemName);
            return true;
        }
        
        return false;
    }
    
    public bool PurchaseItemWithDiscount(ShopItem item, float discountPercent)
    {
        int finalPrice = CalculateDiscountedPrice(item, discountPercent);
        
        if (player.SpendCurrency(finalPrice))
        {
            ApplyItemEffect(item);
            Debug.Log("Purchased: " + item.itemName + " with " + discountPercent + "% discount");
            return true;
        }
        
        return false;
    }
    
    void ApplyItemEffect(ShopItem item)
    {
        switch (item.itemType)
        {
            case "heal":
                player.Heal(item.value);
                break;
            case "currency":
                player.AddCurrency(item.value);
                break;
            case "damage":
                player.attackDamage += item.value;
                Debug.Log("Attack damage increased to " + player.attackDamage);
                break;
            case "defense":
                player.defense += item.value;
                Debug.Log("Defense increased to " + player.defense);
                break;
            case "maxHealth":
                player.maxHealth += item.value;
                player.currentHealth += item.value;
                Debug.Log("Max health increased to " + player.maxHealth);
                break;
            case "level":
                player.level += item.value;
                Debug.Log("Level increased to " + player.level);
                break;
        }
    }
}

public class Combat : MonoBehaviour
{
    private PlayerStats player;
    
    void Start()
    {
        player = GetComponent<PlayerStats>();
    }
    
    public void AttackEnemy(Enemy enemy)
    {
        if (enemy != null && player != null)
        {
            int totalDamage = player.CalculateDamageOutput();
            enemy.TakeDamage(totalDamage);
        }
    }
    
    public int CalculateCriticalDamage(int baseDamage, float critMultiplier)
    {
        return Mathf.FloorToInt(baseDamage * critMultiplier);
    }
    
    public void AttackWithCritChance(Enemy enemy, float critChance, float critMultiplier)
    {
        if (enemy != null && player != null)
        {
            int baseDamage = player.CalculateDamageOutput();
            int finalDamage = baseDamage;
            
            float roll = Random.Range(0f, 100f);
            if (roll < critChance)
            {
                finalDamage = CalculateCriticalDamage(baseDamage, critMultiplier);
                Debug.Log("Critical hit!");
            }
            
            enemy.TakeDamage(finalDamage);
        }
    }
}

public class IAPManager : MonoBehaviour
{
    private PlayerStats player;
    public Dictionary<string, int> iapPrices = new Dictionary<string, int>();
    
    void Start()
    {
        player = FindObjectOfType<PlayerStats>();
        InitializeIAP();
    }
    
    void InitializeIAP()
    {
        iapPrices.Add("currency_small", 99);
        iapPrices.Add("currency_medium", 499);
        iapPrices.Add("currency_large", 999);
        iapPrices.Add("starter_pack", 299);
        iapPrices.Add("premium_pack", 1999);
    }
    
    public void PurchaseIAP(string productId)
    {
        switch (productId)
        {
            case "currency_small":
                player.AddCurrency(1000);
                break;
            case "currency_medium":
                player.AddCurrency(5500);
                break;
            case "currency_large":
                player.AddCurrency(12000);
                break;
            case "starter_pack":
                player.AddCurrency(3000);
                player.attackDamage += 10;
                player.maxHealth += 50;
                player.currentHealth = player.maxHealth;
                break;
            case "premium_pack":
                player.AddCurrency(25000);
                player.attackDamage += 50;
                player.defense += 20;
                player.maxHealth += 100;
                player.currentHealth = player.maxHealth;
                player.level += 5;
                break;
        }
        
        Debug.Log("IAP Purchased: " + productId);
    }
}

public class GameManager : MonoBehaviour
{
    public PlayerStats player;
    public Shop shop;
    public Combat combat;
    
    void Start()
    {
        player = FindObjectOfType<PlayerStats>();
        shop = FindObjectOfType<Shop>();
        combat = FindObjectOfType<Combat>();
    }
    
    void Update()
    {
        if (Input.GetKeyDown(KeyCode.Alpha1))
        {
            TestDamage();
        }
        if (Input.GetKeyDown(KeyCode.Alpha2))
        {
            TestShop();
        }
        if (Input.GetKeyDown(KeyCode.Alpha3))
        {
            TestCombat();
        }
    }
    
    void TestDamage()
    {
        player.TakeDamage(20);
    }
    
    void TestShop()
    {
        if (shop.shopItems.Count > 0)
        {
            shop.PurchaseItem(shop.shopItems[0]);
        }
    }
    
    void TestCombat()
    {
        Enemy enemy = FindObjectOfType<Enemy>();
        if (enemy != null && combat != null)
        {
            combat.AttackEnemy(enemy);
        }
    }
}